import React from "react";
import Slider from "react-slick";

export default function(props) {
  const { title, subtitle, image, items } = props;

  const sliderSettings = {
    className: "certificates",
    arrows: false,
    dots: false,
    speed: 10000,
    slidesToShow: 5,
    slidesToScroll: 5,
    autoplay: true,
    autoplaySpeed: 0,
    cssEase: "linear",
    responsive: [
      // tablet
      {
        breakpoint: 1023,
        settings: {
          slidesToShow: 4,
          slidesToScroll: 4
        }
      },
      // mobile
      {
        breakpoint: 591,
        settings: {
          slidesToShow: 2,
          slidesToScroll: 2
        }
      }
    ]
  };

  return (
    <section id="partners" className="partners-badge partners-badge_v2">
      {/* image */}
      {image && (
        <div
          className="partners-badge__image img-bg"
          style={{ backgroundImage: `url('${image}')` }}
        />
      )}

      {/* info */}
      <div className="partners-badge__container container">
        <div className="row">
          {/* title & subtitle */}
          <div className="col-md-3">
            <h2 className="section__undertitle">{subtitle}</h2>
            <h3 className="section__title">{title}</h3>
          </div>

          {/* items */}
          <div className="col-md-9">
            <div className="certificates-slider__container certificates-slider__container_full">
              <Slider {...sliderSettings}>
                {items &&
                  items.map((item, index) => (
                    <div
                      key={index}
                      className="certificates-item certificates-item_small"
                    >
                      <div className="certificates-item__image">
                        {item.image && (
                          <img src={item.image} alt={item.title} />
                        )}
                      </div>
                    </div>
                  ))}
              </Slider>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
