import React from "react";

export default function({ title, subtitle, items }) {
  return (
    <section className="facts__section">
      <div className="container">
        <h3 className="section__undertitle">{subtitle}</h3>
        <h2 className="section__title">{title}</h2>

        <ul className="facts">
          {items.map((item, index) => (
            <li key={index} className="facts-item">
              <div
                className="facts-item__image"
                style={{
                  backgroundImage: item.image && `url('${item.image}')`
                }}
              />
              <p className="facts-item__description">{item.description}</p>
            </li>
          ))}
        </ul>
      </div>
    </section>
  );
}
