import React from "react";
import { Link } from "react-router-dom";
import Menu from "component/main/Menu";

import Logo from "ico/logo";
import SocialNetworks from "component/main/SocialNetworks";
import HistoryListener from "component/main/HistoryListener";
import Email from "component/main/Email";

export default function(props) {
  const { contacts, menu } = props;

  // scroll offset
  window.addEventListener("scroll", () => {
    const { scrollY: y, innerHeight: offset } = window;
    const { classList } = document.body;

    const css = "header-offset";
    const isExist = [...classList].includes(css);

    if (y > offset * 0.3) {
      !isExist && classList.add(css);
    } else {
      isExist && classList.remove(css);
    }
  });

  return (
    <div>
      {/* header */}
      <header className="app-header">
        <div className="app-header__container container">
          {/* socialNetworks */}
          {contacts && (
            <SocialNetworks
              className="app-header__social-networks"
              items={contacts.socnetworks}
            />
          )}

          {/* email */}
          <Email className="app-header__email" link={contacts.email} />

          {/* logo */}
          <div className="app-header__logo">
            <Logo />
            <Link to="/">Главная</Link>
          </div>
        </div>
      </header>

      {/* menu */}
      <Menu menu={menu} />

      {/* historyListener */}
      <HistoryListener />
    </div>
  );
}
