import { withRouter } from "react-router-dom";

const globalKey = "routeHistoryListener";

// menu line
function menuLineAttach() {
  const { pathname } = window.location;

  const isHomePage = pathname === "/";
  const menuLine = document.querySelector(".menu__line");
  if (menuLine) {
    if (isHomePage) menuLine.removeAttribute("style");
    else {
      const menuLinks = document.querySelectorAll(".menu__list a");
      const linkHref = pathname.split("/")[1];

      const linkElement = [...menuLinks].find(
        el => el.getAttribute("href").indexOf(linkHref) > -1
      );

      if (linkElement) {
        const { offsetLeft: left, clientWidth: width } = linkElement.parentNode;
        menuLine.style.left = `${left + width / 2}px`;
      }
    }
  }
}

function historyListener(pathname) {
  setTimeout(() => {
    menuLineAttach();
  }, 200);

  const { classList } = document.body;

  const globalState = window[globalKey];
  if (globalState.previousPath === pathname) return;
  globalState.previousPath = pathname;

  // hide menu
  classList.remove("menu--active");

  // page home
  const css = "page--home";
  const isHomePage = pathname === "/";
  const isExist = [...classList].includes(css);

  if (isHomePage) !isExist && classList.add(css);
  else isExist && classList.remove(css);
}

export default withRouter(function({ history }) {
  // global state
  if (window[globalKey] === undefined) {
    window[globalKey] = {};
  }

  // history listener
  history.listen(({ pathname }) => {
    historyListener(pathname, history);
  });

  const globalState = window[globalKey];

  // first init
  if (!globalState.firstInit) {
    // resize window event
    window.addEventListener("resize", menuLineAttach);

    setTimeout(() => {
      historyListener(history.location.pathname, history);
    }, 100);
    globalState.firstInit = true;
  }

  return null;
});
