import React from "react";
import { Link } from "react-router-dom";

export default function({ info, index, variant, loading, className }) {
  const css = ["product-badge"];

  if (className) css.push(className);

  if (index !== undefined) css.push(`product-badge--${index}`);
  if (variant) css.push(`product-badge_${variant}`);
  if (loading) css.push("product-badge--loading");

  // info undefined
  if (!info && !loading) css.push("product-badge--undefined");
  if (info && !loading) css.push("product-badge--exist");

  return (
    <div className={css.join(" ")}>
      {info && info.image && <img src={info.image} alt={info.title} />}
      {info && info.link && (
        <Link to={info.link} className="product-badge__link">
          <span className="product-badge__link__text">
            <span>{info.title}</span>
          </span>
        </Link>
      )}
    </div>
  );
}
