import React from "react";
import { Link } from "react-router-dom";

export default function(props) {
  let { variant, children, click, href, medium } = props;

  if (variant === undefined) {
    variant = "default";
  }

  const css = ["btn"];
  const variantCss = {
    default: "btn_default"
  };

  if (variant) css.push(variantCss[variant]);
  if (medium) css.push("btn_md");

  const buttonProps = {
    className: css.join(" "),
    onClick: event => click(event)
  };

  if (href) {
    return (
      <Link to={href} className={css.join(" ")}>
        {children}
      </Link>
    );
  }

  return <button {...buttonProps}>{children}</button>;
}
