import React, { Component } from "react";
import { BrowserRouter as Router } from "react-router-dom";

import api from "api";

import AppLoading from "component/main/AppLoading";
import Header from "component/main/Header";
import Footer from "component/main/Footer";

// pages
import Main from "component/main/Main";

import "css/style.css";

class App extends Component {
  state = {
    isLoading: true
  };

  componentWillMount() {
    document.title = "Sheber";
  }

  componentDidMount() {
    this.getData();
    this.iniHistoryListener();
  }

  getData() {
    api
      .get("main")
      .then(data => {
        this.setState({
          isLoading: false,
          ...data
        });
      })
      .catch(error => {
        console.error(error);
      });
  }

  // history listener
  iniHistoryListener() {
    // const css = [];
    // this.props.history.listen((location, action) => {
    //   console.log("on route change", location, action);
    // });
  }

  render() {
    const { isLoading, contacts, menu, copyright } = this.state;

    // loading
    if (isLoading) {
      return <AppLoading />;
    }

    return (
      <Router>
        <Header contacts={contacts} menu={menu} />

        <Main />

        <Footer contacts={contacts} menu={menu} copyright={copyright} />
      </Router>
    );
  }
}

export default App;
