import React from "react";

export default function({ title, children, variant, close }) {
  const cls = ["dialog dialog--show"];
  if (variant) cls.push(`dialog_${variant}`);

  function onClose() {
    const dialog = document.body.querySelector(".dialog");
    dialog.classList.add("dialog--close");

    setTimeout(() => {
      close();
    }, 500);
  }

  setTimeout(() => {
    const cls = "dialog--show";
    const dialogShow = document.body.querySelector(`.${cls}`);
    if (dialogShow) dialogShow.classList.remove(cls);
  }, 500);

  return (
    <div className={cls.join(" ")}>
      <div className="dialog__bg" onClick={onClose} />
      <button className="dialog__close" onClick={close}>
        Закрыть диалог
      </button>
      <div className="dialog__content">
        {title && (
          <div className="dialog__header">
            <h5 className="dialog__title">{title}</h5>
          </div>
        )}
        <div className="dialog__body">{children}</div>
      </div>
    </div>
  );
}
