import React, { Component } from "react";

import Welcome from "component/home/Welcome2";
import AboutusBadge from "component/home/AboutusBadge";
import CatalogBadge from "component/home/CatalogBadge";
import CharityBadge from "component/home/CharityBadge";
import PartnersBadge from "component/home/PartnersBadge2";

import api from "api";

class Home extends Component {
  state = {
    image: null
  };

  componentDidMount() {
    this.fetchState();
  }

  fetchState() {
    api.get("home").then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });
    });
  }

  render() {
    const {
      longtitle,
      description,
      image,
      images,
      aboutus,
      catalog,
      charity,
      partners
    } = this.state;

    const welcomeProps = {
      longtitle,
      description,
      image,
      images
    };

    return (
      <div className="page-home">
        <Welcome {...welcomeProps} />
        <AboutusBadge {...aboutus} />
        <CatalogBadge {...catalog} />
        <CharityBadge {...charity} />
        <PartnersBadge {...partners} />
      </div>
    );
  }
}
export default Home;
