import React, { Component } from "react";
import Breadcrumbs from "component/main/Breadcrumbs";

import api from "api";

class Article extends Component {
  componentDidMount() {
    this.fetchState();
  }

  fetchState() {
    const paths = window.location.pathname.split("/");
    const params = {
      parent: paths[1],
      alias: paths.pop()
    };

    api.get("article", params).then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });
    });
  }

  render() {
    const { parent, article_subtitle, title, subtitle, content, image } =
      this.state || {};

    if (!title) return <div />;

    let breadcrumbsItems = [{ title }];
    if (parent) breadcrumbsItems = [parent, ...breadcrumbsItems];

    const shareItems = [
      // facebook
      {
        title: "Facebook",
        alias: "facebook",
        link: "https://www.facebook.com/sharer/sharer.php?u=[url]"
      },
      // vk
      {
        title: "VK",
        alias: "vk",
        link: "https://vk.com/share.php?url=[url]title=[title]&image=[image]"
      }
    ].map(({ link, ...innerParams }) => ({
      ...innerParams,
      link: link
        .replace("[title]", encodeURIComponent(title))
        .replace("[url]", encodeURIComponent(window.location.href))
        .replace("[image]", encodeURIComponent(image))
    }));

    return (
      <div>
        <Breadcrumbs items={breadcrumbsItems} />

        <section className="article__section">
          <div className="container">
            {/* header */}
            <div className="article__header">
              <h2 className="section__undertitle">{article_subtitle}</h2>
              <h1 className="section__title">{title}</h1>
            </div>

            {/* info */}
            <div className="row">
              {/* content */}
              <div className="col-md-6">
                <div className="article-info">
                  <h3 className="section__title2">{subtitle}</h3>
                  <div
                    className="content"
                    dangerouslySetInnerHTML={{ __html: content }}
                  />
                </div>
              </div>

              {/* image */}
              <div className="col-md-6">
                <div className="article-image">
                  {image && <img src={image} alt={title} />}
                </div>

                {/* share */}
                <div className="article-share">
                  <p className="article-share__title">Поделиться новостью:</p>
                  <ul className="article-share__items">
                    {shareItems.map((item, index) => (
                      <li
                        key={index}
                        className={`article-share__items__item_${item.alias}`}
                      >
                        <a
                          href={item.link}
                          target="_blank"
                          rel="noopener noreferrer"
                        >
                          {item.title}
                        </a>
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            </div>
          </div>
        </section>
      </div>
    );
  }
}
export default Article;
