import React, { Component } from "react";
import Breadcrumbs from "component/main/Breadcrumbs";
import ProductImages from "component/catalog/ProductImages";

import api from "api";

class Category extends Component {
  state = {
    filters: {}
  };

  componentDidMount() {
    this.fetchState();
  }

  fetchState() {
    const params = {
      alias: window.location.pathname.split("/").pop()
    };

    api.get("catalog/product", params).then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });
    });
  }

  render() {
    const {
      title,
      subtitle,
      build_date,
      square,
      location: cardLocation,
      content,
      images
    } = this.state || {};

    if (!title) return <div />;

    const cards = [
      {
        title: "Год постройки",
        alias: "date",
        value: build_date
      },
      {
        title: "Площадь",
        alias: "square",
        value: square
      },
      {
        title: "Расположение",
        alias: "location",
        value: cardLocation
      }
    ];

    return (
      <div>
        <Breadcrumbs items={[{ title }]} />

        <section className="product__section">
          <div className="container">
            {/* title */}
            <div className="product__header">
              <h3 className="section__undertitle">{subtitle}</h3>
              <h2 className="section__title">{title}</h2>
            </div>

            <div className="row">
              {/* info */}
              <div className="col-lg-6">
                {/* cards */}
                <ul className="product-cards">
                  {cards.map((item, index) => (
                    <li
                      key={index}
                      className={[
                        "product-cards__item",
                        `product-cards__item_${item.alias}`
                      ].join(" ")}
                    >
                      <h5 className="product-cards__item__title">
                        {item.title}
                      </h5>
                      <p className="product-cards__item__value">{item.value}</p>
                    </li>
                  ))}
                </ul>

                <div className="product__info">
                  <h4 className="section__title2">О жилом комплексе</h4>
                  <div
                    className="content"
                    dangerouslySetInnerHTML={{ __html: content }}
                  />
                </div>
              </div>

              {/* images */}
              <div className="col-lg-6">
                <ProductImages items={images} />
              </div>
            </div>
          </div>
        </section>
      </div>
    );
  }
}
export default Category;
