import React from "react";

export default function({ active, variant, click }) {
  const css = [
    "catalog-badge__arrows__item",
    `catalog-badge__arrows__item_${variant}`
  ];

  if (active) {
    css.push("catalog-badge__arrows__item--active");
  }

  const props = {
    className: css.join(" "),
    type: "button",
    disabled: !active,
    variant,
    onClick: click
  };

  return <button {...props} />;
}
