import React, { Component } from "react";
import { Link } from "react-router-dom";
import Breadcrumbs from "component/main/Breadcrumbs";
import { getFormattedDate } from "script/date";

import api from "api";

function NewsItem({ item }) {
  return (
    <div className="news-item">
      {/* image */}
      <Link to={item.link} className="news-item__image">
        <div
          style={{
            backgroundImage: item.image && `url('${item.image}')`
          }}
        />
        <span>Продробнее</span>
      </Link>

      {/* title */}
      <h3 className="news-item__title">
        <Link to={item.link}>{item.title}</Link>
      </h3>
      <time className="news-item__date">
        {getFormattedDate(item.date, "W d.m.Y")}
      </time>
      <p className="news-item__description">{item.description}</p>
    </div>
  );
}

function NewsItems({ group }) {
  return (
    <ul className="news-items__group">
      {group.map((item, itemIndex) => (
        <li key={itemIndex}>
          {/* item */}
          <NewsItem item={item} />
        </li>
      ))}
    </ul>
  );
}

class Charity extends Component {
  componentDidMount() {
    this.fetchState();
  }

  fetchState() {
    api.get("page/news").then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });
    });
  }

  render() {
    const { title, subtitle, items } = this.state || {};

    if (!title) return <div />;

    const newItems = items.reduce(
      (result, item, index) => {
        result[index % 3].push(item);
        return result;
      },
      [[], [], []]
    );
    const newItemsMd = items.reduce(
      (result, item, index) => {
        result[index % 2].push(item);
        return result;
      },
      [[], []]
    );

    return (
      <div>
        <Breadcrumbs items={[{ title }]} />

        <section className="news__section">
          <div className="container">
            <div className="news__header">
              <h2 className="section__undertitle">{subtitle}</h2>
              <h1 className="section__title">{title}</h1>
            </div>

            {/* items */}
            <div>
              {/* desctop */}
              <div className="news-items hidden-md-down">
                {newItems.map((group, index) => (
                  <NewsItems key={index} group={group} />
                ))}
              </div>

              {/* tablet */}
              <div className="news-items hidden-xs hidden-lg-up">
                {newItemsMd.map((group, index) => (
                  <NewsItems key={index} group={group} />
                ))}
              </div>

              {/* mobile */}
              <div className="news-items__group hidden-md-up">
                {items.map((item, index) => (
                  <NewsItem key={index} item={item} />
                ))}
              </div>
            </div>
          </div>
        </section>
      </div>
    );
  }
}
export default Charity;
