import React from "react";

export default function({ className, items }) {
  const css = ["social-networks"];
  if (className) css.push(className);

  return (
    <ul className={css.join(" ")}>
      {items &&
        items.map((item, index) => (
          <li key={index}>
            <span
              className="ico ico_box"
              dangerouslySetInnerHTML={{ __html: item.icon }}
            />
            <a
              className="ico"
              href={item.link}
              target="_blank"
              rel="noopener noreferrer"
            >
              {item.title}
            </a>
          </li>
        ))}
    </ul>
  );
}
