import React, { Component } from "react";

class TextToggle extends Component {
  state = {
    active: false,
    height: null
  };

  toggle = event => {
    const { target } = event;
    const { active } = this.state;

    const newState = {
      active: !active,
      height: null
    };

    const parent = target.parentNode;
    if (!active) {
      const child = parent.getElementsByTagName("div")[0];
      newState.height = child.clientHeight + target.clientHeight / 2;
    }

    this.setState(newState);
  };

  render() {
    const { active, height } = this.state;

    const css = ["toggle-info"];
    const style = {};

    if (active) {
      css.push("toggle-info--active");

      Object.assign(style, {
        height,
        maxHeight: height
      });
    }

    return (
      <div className={css.join(" ")} style={style}>
        <button onClick={this.toggle}>Toggle</button>
        <div>{this.props.children}</div>
      </div>
    );
  }
}

export default TextToggle;
