import React, { Component } from "react";
import Dialog from "component/main/Dialog";
import FormGroup from "component/form/Group";
import Button from "component/main/Button";
import api from "api";

class Aboutus extends Component {
  state = {
    isActive: false,
    isSubccess: false,

    fields: [
      // name
      {
        title: "Имя",
        name: "name"
      },
      // email
      {
        title: "Email",
        name: "email",
        type: "email",
        required: true
      },
      // file
      {
        title: "Резюме",
        name: "file",
        type: "file",
        required: true
      }
    ],

    form: {},
    errors: {}
  };

  componentWillReceiveProps({ info }) {
    const { title } = info || {};
    if (!title) return;

    this.setState({
      isActive: true,
      isSubccess: false,
      form: {},
      errors: {}
    });

    const { classList } = document.body;
    const cls = "dialog--body";
    if (!classList.contains(cls)) classList.add(cls);
  }

  onClose = () => {
    this.setState({ isActive: false });

    const { classList } = document.body;
    const cls = "dialog--body";
    if (classList.contains(cls)) classList.remove(cls);
  };

  onChange = ({ name, value }) => {
    const { form, errors } = this.state;

    const newState = {
      form: {
        ...form,
        [name]: value
      }
    };

    if (errors[name] !== undefined) {
      const newErrors = { ...errors };
      delete newErrors[name];
      newState.errors = newErrors;
    }

    this.setState(newState);
  };
  onSubmit = event => {
    event.preventDefault();

    const { fields, form } = this.state;

    const newErrors = fields.reduce((result, { name, required }) => {
      if (required && !form[name]) {
        result[name] = "Обязательное поле";
      }
      return result;
    }, {});

    if (Object.keys(newErrors).length) {
      this.setState({
        errors: newErrors
      });
      return;
    }

    (async () => {
      try {
        const params = new FormData();
        const extraParams = {
          position: this.props.info.title,
          url: window.location.href
        };

        Object.entries({ ...form, ...extraParams }).forEach(([name, value]) => {
          params.append(name, value);
        });

        await api.post("request/resume", params);
        this.setState({
          isSubccess: true
        });
      } catch ({ response }) {
        const { data } = response;
        this.setState({
          errors: data.errors || {}
        });
      }
    })();
  };

  render() {
    const { isActive, isSubccess, fields, errors } = this.state;
    if (!isActive) return null;

    const { title } = this.props.info;

    return (
      <Dialog title="Отправить резюме" close={this.onClose}>
        <p className="dialog-description">
          Позиция «<strong>{title}</strong>»
        </p>

        <form onSubmit={this.onSubmit} className={isSubccess ? "hide" : null}>
          {fields.map((field, index) => (
            <FormGroup
              key={index}
              {...field}
              error={errors[field.name]}
              change={this.onChange}
            />
          ))}

          <div className="form-btn">
            <Button variant="default" click={this.onSubmit}>
              отправить
            </Button>
          </div>
        </form>

        <div className={!isSubccess ? " hide" : null}>
          <div className="alert">Ваш запрос прошел успешно!</div>
          <div className="form-btn">
            <Button variant="default" click={this.onClose}>
              закрыть
            </Button>
          </div>
        </div>
      </Dialog>
    );
    // return (<Dialog/>);
  }
}
export default Aboutus;
