import React, { Component } from "react";
import Breadcrumbs from "component/main/Breadcrumbs";

import api from "api";

class Aboutus extends Component {
  componentDidMount() {
    this.fetchState();
  }

  fetchState() {
    api.get("page/contacts").then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });
    });
  }

  render() {
    const {
      title,
      subtitle,
      description,
      map,
      mapLink,
      address,
      email,
      phones,
      worktimes
    } = this.state || {};

    if (!title) return <div />;

    return (
      <div className="contacts-page">
        <Breadcrumbs items={[{ title }]} />

        <section className="contacts-section">
          {/* header */}
          <div className="container">
            <div className="contacts-header">
              <h2 className="section__undertitle">{subtitle}</h2>
              <h1 className="section__title">{title}</h1>
            </div>
          </div>

          {/* map & info */}
          <div className="contacts">
            <iframe src={map} title="Contacts map" />
            <div className="contacts__container container">
              <div className="contacts-info">
                <h3 className="contacts-info__title">{description}</h3>

                {/* address */}
                <div className="contacts-info__group">
                  <h4 className="contacts-info__group__title">Адрес офиса:</h4>
                  <p
                    className="contacts-info__group__value"
                    dangerouslySetInnerHTML={{
                      __html: mapLink
                        ? `<a href="${mapLink}" target="_blank" rel="noopener noreferrer">${address}</a>`
                        : address
                    }}
                  />
                </div>

                {/* email */}
                <div className="contacts-info__group">
                  <h4 className="contacts-info__group__title">E-mail:</h4>
                  <p
                    className="contacts-info__group__value"
                    dangerouslySetInnerHTML={{
                      __html: `<a href="mailto:${email}">${email}</a>`
                    }}
                  />
                </div>

                {/* phone */}
                <div className="contacts-info__group">
                  <h4 className="contacts-info__group__title">Телефон:</h4>
                  <p
                    className="contacts-info__group__value"
                    dangerouslySetInnerHTML={{
                      __html:
                        phones &&
                        phones
                          .map(
                            phone =>
                              `<a href="tel:${phone
                                .replace(/\D/g, "")
                                .replace(/^[87]?/, "+7")}">${phone}</a>`
                          )
                          .join("\n")
                    }}
                  />
                </div>

                {/* worktime */}
                <div className="contacts-info__group">
                  <h4 className="contacts-info__group__title">
                    График работы:
                  </h4>
                  <p className="contacts-info__group__value">{worktimes}</p>
                </div>
              </div>
            </div>
          </div>
        </section>
      </div>
    );
  }
}
export default Aboutus;
