import React, { Component } from "react";
import Breadcrumbs from "component/main/Breadcrumbs";
import Email from "component/main/Email";
import Button from "component/main/Button";
import VacancyDialog from "component/main/VacancyDialog";

import api from "api";

class Aboutus extends Component {
  state = {
    clsActive: "vacancies-item--active",
    clsBody: "vacancies-item__body",

    activeItem: null
  };

  componentDidMount() {
    this.fetchState();
    this.initResizeEvent();
  }

  fetchState() {
    api.get("page/vacancy").then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });

      setTimeout(() => {
        this.onToggle(0);
      }, 100);
    });
  }

  initResizeEvent() {
    if (window.vacancyResizeEventInited) return;
    window.vacancyResizeEventInited = true;

    window.addEventListener("resize", () => {
      this.setItemHeader();
    });
  }

  onToggle = index => {
    const { clsActive, clsBody } = this.state;
    const items = document.body.querySelectorAll(".vacancies-item");

    // clear previous state of dom
    [...items].forEach(item => {
      item.classList.remove(clsActive);

      const body = item.querySelector(`.${clsBody}`);
      if (body) body.removeAttribute("style");
    });

    const activeItem = items[index];
    if (activeItem) activeItem.classList.add(clsActive);

    this.setItemHeader();
  };
  setItemHeader() {
    const { clsActive, clsBody } = this.state || {};
    if (!clsActive || !clsBody) return;

    const activeItem = document.body.querySelector(`.${clsActive}`);
    const body = activeItem && activeItem.querySelector(`.${clsBody}`);

    if (activeItem && body) {
      body.removeAttribute("style");

      body.style.height = [
        activeItem.querySelector(".vacancies-item__body__inner").clientHeight,
        "px"
      ].join("");
    }
  }

  onSendResume = item => {
    this.setState({
      activeItem: item
    });
  };
  onCloseDialog = () => {
    this.setState({
      activeItem: null
    });
  };

  render() {
    const { title, subtitle, email, content, image, items, activeItem } =
      this.state || {};

    if (!title) return null;

    return (
      <div>
        <Breadcrumbs items={[{ title }]} />

        <section className="main__header">
          <div className="container">
            <h2 className="section__undertitle">{subtitle}</h2>
            <h1 className="section__title">{title}</h1>
          </div>
        </section>

        <section className="vacancy-section">
          <div className="container">
            <div className="row">
              <div className="col-md-5">
                {image && (
                  <div className="vacancy-image">
                    <img src={image} alt={title} />
                  </div>
                )}

                <div
                  className="vacancy-content"
                  dangerouslySetInnerHTML={{ __html: content }}
                />

                {email && <Email className="vacancy-email" link={email} />}
              </div>

              <div className="col-md-7">
                <ul className="vacancies">
                  {items.map((item, index) => (
                    <li key={index} className="vacancies-item">
                      <h3
                        className="vacancies-item__header"
                        onClick={() => this.onToggle(index)}
                      >
                        {item.title}
                      </h3>
                      <div className="vacancies-item__body">
                        <div className="vacancies-item__body__inner">
                          <ul>
                            <li>
                              <h4>Требования к кандидату</h4>
                              <p
                                dangerouslySetInnerHTML={{
                                  __html: item.requiments
                                }}
                              />
                            </li>
                            <li>
                              <h4>Условия</h4>
                              <p
                                dangerouslySetInnerHTML={{
                                  __html: item.conditions
                                }}
                              />
                            </li>
                          </ul>

                          <div className="vacancies-item__btn">
                            <Button
                              medium
                              click={() => this.onSendResume(item)}
                            >
                              Отправить резюме
                            </Button>
                          </div>
                        </div>
                      </div>
                    </li>
                  ))}
                </ul>
              </div>
            </div>
          </div>
        </section>

        {/* dialog */}
        <VacancyDialog info={activeItem} close={this.onCloseDialog} />
      </div>
    );
  }
}
export default Aboutus;
