import api from "api";

export default ({ filters, selectedCategory }) => {
  if (selectedCategory) {
    filters.parent = selectedCategory.id;
  }

  return new Promise((resolve, reject) => {
    api
      .get("catalog/items", filters)
      .then(data => {
        const { items, pagination } = data;

        resolve({
          catalogItems: items,
          pagination
        });
      })
      .catch(error => {
        reject(error);
      });
  });
};
