import React from "react";

export default function({ title, type, change, error, ...props }) {
  const fieldProps = {
    ...props,
    className: "form-control"
  };

  function formChange({ target }) {
    const { name, value } = target;
    change({ name, value });
  }

  if (type !== "textarea") fieldProps.type = type || "text";
  if (type === "file") {
    fieldProps.onChange = function(event) {
      const { target } = event;
      const [file] = target.files;

      const parent = target.parentNode;
      const clsExist = "form-file--exist";
      const span = parent.querySelector("span");

      if (file) {
        span.textContent = file.name;
        parent.classList.add(clsExist);
      } else {
        span.textContent = "";
        parent.classList.remove(clsExist);
      }

      if (change) {
        change({
          name: target.name,
          value: file
        });
      }
    };
  }

  if (fieldProps.onChange === undefined) fieldProps.onChange = formChange;

  // className
  const cls = ["form-group"];
  let newTitle = title;

  if (error !== undefined) {
    cls.push("form-group--error");
    if (typeof error === "string") newTitle = error;
  }

  return (
    <div className={cls.join(" ")}>
      <label className="form-label">{newTitle}</label>
      {type === "textarea" ? (
        <textarea {...fieldProps} />
      ) : type === "file" ? (
        <label className="form-file">
          <input {...fieldProps} />
          <span />
        </label>
      ) : (
        <input {...fieldProps} />
      )}
    </div>
  );
}
