import React from "react";
import Slider from "react-slick";
import Button from "component/main/Button";
import { animateScroll } from "react-scroll";

function onBtnClick() {
  const projects = document.body.querySelector("#projects");
  if (!projects) return;

  let position = projects.offsetTop;

  const nav = document.body.querySelector("nav");
  if (nav && window.innerWidth >= 1024) position -= nav.clientHeight;

  animateScroll.scrollTo(position);
}

function WelcomeSlider(items) {
  const props = {
    className: "certificates",
    arrows: false,
    dots: false,
    fade: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 5000
  };

  return (
    <div className="background-slider">
      <Slider {...props}>
        {items.map((item, index) => (
          <div key={index} className="background-slider__item">
            <div
              className="background-slider__item__image"
              style={{ backgroundImage: `url('${item}')` }}
            />
          </div>
        ))}
      </Slider>
    </div>
  );
}

export default function(props) {
  const { longtitle, description, images } = props;

  return (
    <section className="section-welcome">
      {Array.isArray(images) && images.length && WelcomeSlider(images)}

      <div className="container">
        <div className="welcome__info">
          <h1>{longtitle}</h1>
          <p>{description}</p>
        </div>

        <div className="welcome__btn">
          <Button click={onBtnClick}>Проекты</Button>
        </div>
      </div>
    </section>
  );
}
