import React, { Component } from "react";
import Breadcrumbs from "component/main/Breadcrumbs";
import ProductBadge from "component/catalog/ProductBadge";
import fetchItems from "component/catalog/fetchItems";

import api from "api";

class Category extends Component {
  state = {
    filters: {
      limit: 30
    }
  };

  componentDidMount() {
    this.fetchState();
    this.fetchItems();
  }

  fetchState() {
    api.get("catalog").then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });
    });
  }

  fetchItems() {
    this.setState({ isLoading: true });

    (async () => {
      try {
        const data = await fetchItems(this.state);
        this.setState({ ...data });
      } catch (error) {
        console.error(error);
      }
      this.setState({ isLoading: false });
    })();
  }

  onSelectCategory = (event, item) => {
    event.preventDefault();

    let newValue = null;
    if (item) newValue = { ...item };

    this.setState({
      selectedCategory: newValue
    });

    setTimeout(() => {
      this.fetchItems();
    }, 100);
  };

  render() {
    const {
      title,
      subtitle,
      description,
      items,
      catalogItems,
      selectedCategory
    } = this.state || {};

    if (!title) return <div />;

    const newItems = [
      {
        title: "Все проекты",
        description,
        link: "/catalog/"
      },
      ...items
    ];

    const categoryInfo = selectedCategory || newItems[0];

    return (
      <div>
        <Breadcrumbs items={[{ title }]} />

        <section className="catalog__section">
          <div className="container">
            {/* title */}
            <div className="catalog__header">
              <h3 className="section__undertitle">{subtitle}</h3>
              <h2 className="section__title">{title}</h2>
            </div>

            <div className="row">
              {/* menu */}
              <div className="col-md-4">
                <ul className="catalog-menu">
                  {newItems.map((item, index) => (
                    <li
                      key={index}
                      className={
                        categoryInfo.title === item.title ? "active" : null
                      }
                    >
                      <a
                        href={item.link}
                        onClick={event => this.onSelectCategory(event, item)}
                      >
                        {item.menutitle || item.title}
                      </a>
                    </li>
                  ))}
                </ul>
              </div>

              {/* title, description, items */}
              <div className="col-md-8">
                {/* title & descirption */}
                <div className="catalog-info">
                  <h4 className="section__title2">{categoryInfo.title}</h4>
                  <p className="section__description">
                    {categoryInfo.description}
                  </p>
                </div>

                {/* items */}
                <div className="row">
                  {catalogItems &&
                    catalogItems.map((item, index) => (
                      <div className="col-sm-6" key={index}>
                        <ProductBadge info={item} />
                      </div>
                    ))}
                </div>
              </div>
            </div>
          </div>
        </section>
      </div>
    );
  }
}
export default Category;
