import React, { Component } from "react";
import ProductBadge from "component/catalog/ProductBadge";
import Button from "component/main/Button";
import Arrow from "component/catalog/BadgeArrow";
import fetchItems from "component/catalog/fetchItems";

function Arrows({ items, pagination, click }) {
  if (!pagination || !items.length) return null;
  return (
    <div className="catalog-badge__arrows">
      <Arrow variant="left" active={true} click={click} />
      <Arrow variant="right" active={true} click={click} />
    </div>
  );
}

function getItemImage(item, index) {
  if (!item) return undefined;
  const { images } = item;
  if (!images || !Array.isArray(images) || !images.length) return undefined;

  return images[index];
}

class CatalogBadge extends Component {
  state = {
    isLoading: true,

    selectedCategory: null,
    filters: {
      page: 1,
      limit: 10
    },
    catalogItems: [],

    selectedItemIndex: 0
  };

  componentDidMount() {
    this.initCategory();
  }

  initCategory() {
    const { items } = this.props;
    if (!items || !items.length) return;

    this.setState({
      selectedCategory: items[0]
    });

    setTimeout(() => {
      this.fetchItems();
    }, 100);
  }

  fetchItems() {
    this.setState({ isLoading: true });

    setTimeout(() => {
      (async () => {
        try {
          const data = await fetchItems(this.state);
          this.setState({ ...data, isLoading: false });
        } catch (error) {
          console.error(error);
        }
      })();
    }, 300);
  }

  onSelectCategory(event, item) {
    event.preventDefault();

    let newValue = null;

    if (item) {
      newValue = { ...item };
    }

    this.setState({
      selectedCategory: newValue,
      filters: {
        page: 1,
        limit: 10
      }
    });

    setTimeout(() => {
      this.fetchItems();
    }, 100);
  }

  onSlide = ({ target }) => {
    const variant = target.getAttribute("variant");
    let { selectedItemIndex, catalogItems } = this.state;
    const length = catalogItems.length;

    if (selectedItemIndex === -1) return;

    if (variant === "left") {
      selectedItemIndex -= 1;
      if (selectedItemIndex < 0) selectedItemIndex = length - 1;
    }
    if (variant === "right") {
      selectedItemIndex += 1;
      if (selectedItemIndex > length - 1) selectedItemIndex = 0;
    }

    this.setState({ isLoading: true, selectedItemIndex: -1 });
    setTimeout(() => {
      this.setState({ isLoading: false, selectedItemIndex });
    }, 300);
  };

  render() {
    const { items } = this.props;
    const {
      isLoading,
      selectedCategory,
      catalogItems,
      selectedItemIndex,
      pagination
    } = this.state;

    if (!items || !Array.isArray(items)) return null;

    const selectedItem = catalogItems[selectedItemIndex];

    return (
      <div className="row">
        {/* menu & 1-3 items */}
        <div className="col-md-7 col-lg-6">
          <div className="row">
            {/* menu & 2 item */}
            <div className="col-md-6">
              {/* menu */}
              <div className="catalog-badge__menu__container">
                <ul className="catalog-badge__menu">
                  {items.map((item, index) => (
                    <li
                      key={index}
                      className={
                        selectedCategory && item.id === selectedCategory.id
                          ? "catalog-badge__menu__item--active"
                          : null
                      }
                    >
                      <a
                        href={item.link}
                        onClick={event => this.onSelectCategory(event, item)}
                      >
                        {item.menutitle || item.title}
                      </a>
                    </li>
                  ))}
                </ul>

                <Button href="/catalog">Все проекты</Button>
              </div>

              {/* 2 item */}
              {
                <ProductBadge
                  className="hidden-xs"
                  info={{ image: getItemImage(selectedItem, 1) }}
                  loading={isLoading}
                />
              }

              {/* mobile */}
              <div className="hidden-md-up">
                <Arrows
                  items={catalogItems}
                  pagination={pagination}
                  click={this.onSlide}
                />

                <ProductBadge info={selectedItem} loading={isLoading} />
              </div>
            </div>

            {/* 1, 3 items */}
            <div className="col-md-6 hidden-xs">
              {
                <ProductBadge
                  info={{ image: getItemImage(selectedItem, 0) }}
                  loading={isLoading}
                />
              }
              {
                <ProductBadge
                  info={{ image: getItemImage(selectedItem, 2) }}
                  loading={isLoading}
                />
              }
            </div>
          </div>
        </div>

        {/* loading & arrows & 4 item */}
        <div className="col-md-5 col-lg-6 hidden-xs">
          <Arrows
            items={catalogItems}
            pagination={pagination}
            click={this.onSlide}
          />

          {/* 4 item */}
          <ProductBadge info={selectedItem} loading={isLoading} index="3" />
        </div>
      </div>
    );
  }
}

export default CatalogBadge;
