import React, { Component } from "react";
import Breadcrumbs from "component/main/Breadcrumbs";
import MainInfo from "component/aboutus/MainInfo";
import StatisticsContainer from "component/aboutus/StatisticsContainer";
import Facts from "component/aboutus/Facts";
import Certificates from "component/aboutus/Certificates";

import api from "api";

class Aboutus extends Component {
  componentDidMount() {
    this.fetchState();
  }

  fetchState() {
    api.get("page/aboutus").then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });
    });
  }

  render() {
    const { title, subtitle, content, image, statistics, facts, certificates } =
      this.state || {};

    return (
      <div>
        <Breadcrumbs items={[{ title }]} />

        <MainInfo {...{ title, subtitle, content, image }} />
        {statistics && <StatisticsContainer items={statistics} />}
        {facts && <Facts {...facts} />}
        {certificates && <Certificates {...certificates} />}
      </div>
    );
  }
}
export default Aboutus;
