import React from "react";
import { Link } from "react-router-dom";
import { animateScroll } from "react-scroll";

function onToggle() {
  const { classList } = document.body;

  const css = "menu--active";
  const isExist = [...classList].includes(css);

  if (isExist) classList.remove(css);
  else {
    classList.add(css);
    animateScroll.scrollToTop({
      duration: 200
    });
  }
}

export default function(props) {
  const { menu } = props;

  const css = ["menu"];

  // location home
  if (window.location.pathname === "/") {
    css.push("menu_light");
  }

  const newMenu = menu.filter(item => item.link !== "/vacancy.html");

  return (
    <div className={css.join(" ")}>
      <button className="menu-btn" onClick={onToggle}>
        Открыть меню
      </button>

      <nav>
        <div className="menu__container container">
          <ul className="menu__list">
            {[0, 1].map(group => (
              <li key={group}>
                <ul>
                  {newMenu
                    .filter(
                      (item, index) =>
                        index >= group * 3 && index < group * 3 + 3
                    )
                    .map((item, index) => (
                      <li key={index}>
                        {item.blank ? (
                          <a
                            href={item.blank}
                            target="_blank"
                            rel="noopener noreferrer"
                          >
                            {item.menutitle || item.title}
                          </a>
                        ) : (
                          <Link to={item.link}>
                            {item.menutitle || item.title}
                          </Link>
                        )}
                      </li>
                    ))}
                </ul>
              </li>
            ))}
          </ul>
        </div>
        <i className="menu__line" />
      </nav>
    </div>
  );
}
