import React from "react";
import Slider from "react-slick";

export default function({ title, subtitle, description, image, items }) {
  const sliderSettings = {
    className: "certificates",
    arrows: false,
    dots: false,
    speed: 10000,
    slidesToShow: 3,
    slidesToScroll: 3,
    autoplay: true,
    autoplaySpeed: 0,
    cssEase: "linear",
    responsive: [
      // tablet
      {
        breakpoint: 1023,
        settings: {
          slidesToShow: 2,
          slidesToScroll: 2
        }
      },
      // mobile
      {
        breakpoint: 591,
        settings: {
          slidesToShow: 1,
          slidesToScroll: 1
        }
      }
    ]
  };

  return (
    <section className="certificates__section">
      <div className="container">
        <div className="row row_between">
          {/* info */}
          <div className="col-md-4">
            <div className="certificates__info">
              <h3 className="section__undertitle">{subtitle}</h3>
              <h2 className="section__title">{title}</h2>
              <p className="section__description">{description}</p>

              <div
                className="certificates__info__image"
                style={{ backgroundImage: image && `url('${image}')` }}
              />
            </div>
          </div>

          {/* items */}
          <div className="col-md-8">
            <div className="certificates-slider__container">
              <Slider {...sliderSettings}>
                {items.map((item, index) => (
                  <div key={index} className="certificates-item">
                    <div
                      className="certificates-item__image"
                      style={{
                        backgroundImage: item.image && `url('${item.image}')`
                      }}
                    />
                  </div>
                ))}
              </Slider>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
