import React from "react";
import Button from "component/main/Button";
import { getFormattedDate } from "script/date";

export default function(props) {
  const { title, subtitle, link, image, items } = props;

  return (
    <section id="charity" className="charity-badge">
      <div className="charity-badge__container container">
        {/* title, subtitle, items */}
        <div className="row row_end">
          <div className="col-md-3 col-lg-5">
            <div className="charity-badge__image__container">
              {image && (
                <div
                  className="charity-badge__image img-bg"
                  style={{ backgroundImage: `url('${image}')` }}
                />
              )}
            </div>
          </div>

          <div className="col-md-9 col-lg-7">
            <div className="charity-badge__info">
              <h2 className="section__undertitle">{subtitle}</h2>
              <h3 className="section__title">{title}</h3>

              {items && (
                <ul className="charity-badge__items">
                  {items.map((item, index) => (
                    <li key={index}>
                      <p>{item.description}</p>
                      <time
                        className="article-date"
                        dateTime={item.publishedon}
                      >
                        {getFormattedDate(item.publishedon, "W d.m.Y")}
                      </time>
                    </li>
                  ))}
                </ul>
              )}

              {link && <Button href={link}>Подробнее</Button>}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
