import React, { Component } from "react";
import { Link } from "react-router-dom";
import Breadcrumbs from "component/main/Breadcrumbs";
import { getFormattedDate } from "script/date";

import api from "api";

class Charity extends Component {
  componentDidMount() {
    this.fetchState();
  }

  fetchState() {
    api.get("page/charity").then(data => {
      const { title } = data;

      // set head title
      if (title) {
        document.title = title;
      }

      this.setState({
        ...data
      });
    });
  }

  render() {
    const { title, subtitle, items } = this.state || {};

    if (!title) return <div />;

    return (
      <div>
        <Breadcrumbs items={[{ title }]} />

        <section className="charity-catalog__section">
          <div className="container">
            <div className="charity-catalog__header">
              <h2 className="section__undertitle">{subtitle}</h2>
              <h1 className="section__title">{title}</h1>
            </div>

            {/* items */}
            <ul className="charity-catalog__items">
              {items.map((item, index) => (
                <li key={index} className="charity-catalog__items__item">
                  <div className="row">
                    {/* image */}
                    <div className="col-md-5">
                      <Link
                        to={item.link}
                        style={{
                          backgroundImage: item.image && `url('${item.image}')`
                        }}
                        className="charity-catalog__items__item__image"
                      >
                        <span>Подробнее</span>
                      </Link>
                    </div>

                    {/* info */}
                    <div className="col-md-7">
                      <div className="charity-catalog__items__item__info">
                        <h3 className="charity-catalog__items__item__title">
                          <Link to={item.link}>{item.title}</Link>
                        </h3>

                        <p className="charity-catalog__items__item__description">
                          {item.description}
                        </p>

                        <time className="article-date" dateTime={item.date}>
                          {getFormattedDate(item.date, "W d.m.Y")}
                        </time>
                      </div>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </section>
      </div>
    );
  }
}
export default Charity;
