import React from "react";
import { Link } from "react-router-dom";
import LogoIcon from "ico/logo-icon";
import SocialNetworks from "component/main/SocialNetworks";

export default function({ contacts, menu, copyright }) {
  const css = ["app-header"];
  const cssMenu = ["menu"];

  // location home
  if (window.location.pathname === "/") {
    css.push("app-header_light");
    cssMenu.push("menu_light");
  }

  return (
    <footer id="footer" className="app-footer">
      <section className="app-footer__row1">
        <div className="container">
          <ul className="menu_footer">
            <li>
              <LogoIcon />
            </li>
            {menu &&
              menu.map((item, index) => (
                <li key={index}>
                  <Link to={item.link}>{item.menutitle || item.title}</Link>
                </li>
              ))}
          </ul>
        </div>
      </section>
      <section className="app-footer__row2">
        <div className="container">
          <div className="app-footer__row2__container">
            {/* social networks */}
            {contacts && (
              <SocialNetworks
                className="app-footer__social-networks"
                items={contacts.socnetworks}
              />
            )}

            {/* email */}
            {contacts && (
              <a
                className="app-footer__email-link email-link"
                href={`mailto:${contacts.email}`}
              >
                {contacts.email}
              </a>
            )}

            {/* copyright */}
            <div className="app-footer__copyright copyright">{copyright}</div>
          </div>
        </div>
      </section>
    </footer>
  );
}
