export function getFormattedDate(dateString, format) {
  const date = new Date(dateString);

  let day = date.getDate();
  let month = date.getMonth();

  if (Number(day) < 10) day = [0, day].join("");
  if (Number(month) < 10) month = [0, month].join("");

  // week
  let week = [
    "Воскресенье",
    "Понедельник",
    "Вторник",
    "Среда",
    "Четверг",
    "Пятница",
    "Суббота"
  ][date.getDay()];

  return format
    .replace(/W/g, week)
    .replace(/d/g, day)
    .replace(/m/g, month)
    .replace(/Y/g, date.getFullYear());
}

export default {};
