import React from "react";

export default function({ items }) {
  return (
    <ul className="aboutus-stats">
      {items.map((item, index) => (
        <li
          key={index}
          dangerouslySetInnerHTML={{
            __html: item.replace("[", "<span>").replace("]", "</span>")
          }}
        />
      ))}
    </ul>
  );
}
