import React, { Component } from "react";
import Slider from "react-slick";

function ImagesItem({ type, title, image }) {
  return (
    <div className={`product-images__${type}__item`}>
      <div
        className={`product-images__${type}__item__image`}
        style={{ backgroundImage: image && `url('${image}')` }}
        alt={title}
      />
    </div>
  );
}

class ProductImages extends Component {
  state = {
    main: null,
    switcher: null
  };

  componentDidMount() {
    this.setState({
      main: this.sliderMain,
      switcher: this.sliderSwitcher
    });
  }

  render() {
    const { items } = this.props;
    const { main, switcher } = this.state;

    if (!items || !Array.isArray(items) || !items.length) return null;

    const settings = {
      ref: slider => (this.sliderMain = slider),
      className: "product-images__main",
      asNavFor: switcher,
      fade: true,
      dots: false,
      slidesToShow: 1,
      slidesToScroll: 1
    };
    const switcherSettings = {
      ref: slider => (this.sliderSwitcher = slider),
      className: "product-images__switcher hidden-xs",
      asNavFor: main,
      arrows: false,
      dots: false,
      focusOnSelect: true,
      slidesToShow: 3,
      slidesToScroll: 3
    };

    return (
      <div className="product-images">
        {/* main */}
        <Slider {...settings}>
          {items.map((item, index) => (
            <ImagesItem key={index} {...item} type="main" />
          ))}
        </Slider>

        {/* switcher */}
        <Slider {...switcherSettings}>
          {items.map((item, index) => (
            <ImagesItem key={index} {...item} type="switcher" />
          ))}
        </Slider>
      </div>
    );
  }
}
export default ProductImages;
